<h2 style="margin-bottom:20px">Gestion des catégories</h2><div style="margin-bottom:16px"><a href="/admin/categories/create"style="padding:10px 14px;background:#667eea;color:#fff;text-decoration:none;border-radius:5px">+ Nouvelle catégorie</a></div><?php if(!empty($categories)): ?><table style="width:100%;background:#fff;border-collapse:collapse;box-shadow:0 2px 8px rgba(0,0,0,.1)"><thead><tr style="background:#f1f3f5"><th style="padding:10px;text-align:left">ID</th><th style="padding:10px;text-align:left">Nom</th><th style="padding:10px;text-align:left">Créée le</th><th style="padding:10px;text-align:left">Actions</th></tr></thead><tbody><?php foreach($categories as $category): ?><tr><td style="padding:10px;border-top:1px solid #eee"><?=(int)$category['id']?></td><td style="padding:10px;border-top:1px solid #eee"><?=htmlspecialchars($category['name'])?></td><td style="padding:10px;border-top:1px solid #eee"><?=htmlspecialchars(date('d/m/Y H:i',strtotime($category['created_at'])))?></td><td style="padding:10px;border-top:1px solid #eee;display:flex;gap:10px;align-items:center"><a href="/admin/categories/<?=(int)$category['id']?>/edit">Modifier</a><form action="/admin/categories/<?=(int)$category['id']?>/delete"method="post"onsubmit='return confirm("Supprimer cette catégorie ?")'style="display:inline"><button style="background:#dc3545;color:#fff;border:0;border-radius:4px;padding:6px 10px;cursor:pointer"type="submit">Supprimer</button></form></td></tr><?php endforeach; ?></tbody></table><?php else: ?><p>Aucune catégorie enregistrée.</p><?php endif; ?>